def apply_calls(state, calls):
    result = dict(state)
    for call in calls:
        if call["op"] == "set":
            result[call["key"]] = call["value"]
        elif call["op"] == "delete":
            result.pop(call["key"], None)
    return result

def states_match(end_state, expected):
    return end_state == expected

def grade(seed, calls, expected):
    return states_match(apply_calls(seed, calls), expected)

